import{_ as d,o as r,c as o,a2 as l}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"灵根系统","description":"","frontmatter":{},"headers":[],"relativePath":"guide/linggen.md","filePath":"guide/linggen.md","lastUpdated":null}'),a={name:"guide/linggen.md"};function i(e,t,n,s,h,g){return r(),o("div",null,[...t[0]||(t[0]=[l('<h1 id="灵根系统" tabindex="-1">灵根系统 <a class="header-anchor" href="#灵根系统" aria-label="Permalink to &quot;灵根系统&quot;">​</a></h1><p>灵根是修仙的根基，决定了修士的修炼方向和功法契合度。</p><h2 id="灵根类型总览" tabindex="-1">灵根类型总览 <a class="header-anchor" href="#灵根类型总览" aria-label="Permalink to &quot;灵根类型总览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>灵根</th><th>描述</th><th>觉醒权重</th><th>突破加成</th><th>灵气恢复</th><th>防御倍率</th><th>生命恢复</th><th>同灵根功法倍率</th><th>所有功法倍率</th></tr></thead><tbody><tr><td><strong>无灵根</strong></td><td>无法修炼</td><td>0%</td><td>+0%</td><td>×1.0</td><td>×1.0</td><td>+0</td><td>×1.0</td><td>×1.0</td></tr><tr><td><strong>金灵根</strong></td><td>攻击力突出</td><td>19%</td><td>+10%</td><td>×1.0</td><td>×1.0</td><td>+0</td><td>×1.5</td><td>×1.0</td></tr><tr><td><strong>木灵根</strong></td><td>灵气充沛</td><td>19%</td><td>+5%</td><td>×1.5</td><td>×1.0</td><td>+5</td><td>×1.5</td><td>×1.0</td></tr><tr><td><strong>水灵根</strong></td><td>魔力充裕</td><td>19%</td><td>+5%</td><td>×1.3</td><td>×1.0</td><td>+0</td><td>×1.5</td><td>×1.0</td></tr><tr><td><strong>火灵根</strong></td><td>伤害爆发</td><td>19%</td><td>+5%</td><td>×1.0</td><td>×1.0</td><td>+0</td><td>×1.5</td><td>×1.0</td></tr><tr><td><strong>土灵根</strong></td><td>防御坚固</td><td>19%</td><td>+5%</td><td>×1.0</td><td>×1.15</td><td>+0</td><td>×1.5</td><td>×1.0</td></tr><tr><td><strong>天灵根</strong></td><td>全才全能</td><td>5%</td><td>+20%</td><td>×2.0</td><td>×1.1</td><td>+2</td><td>×1.5</td><td>×1.2</td></tr></tbody></table><hr><h2 id="各灵根详解" tabindex="-1">各灵根详解 <a class="header-anchor" href="#各灵根详解" aria-label="Permalink to &quot;各灵根详解&quot;">​</a></h2><h3 id="🔶-金灵根" tabindex="-1">🔶 金灵根 <a class="header-anchor" href="#🔶-金灵根" aria-label="Permalink to &quot;🔶 金灵根&quot;">​</a></h3><blockquote><p><strong>&quot;攻击力 +15%，突破成功率 +10%&quot;</strong></p></blockquote><ul><li>定位：<strong>战斗输出型</strong></li><li>突出优势：突破成功率加成最高（+10%），仅次于天灵根</li><li>功法契合：全金系功法享受 <strong>1.5倍威力</strong></li><li>适合玩家：喜欢正面战斗、追求高输出的修士</li></ul><h3 id="🌿-木灵根" tabindex="-1">🌿 木灵根 <a class="header-anchor" href="#🌿-木灵根" aria-label="Permalink to &quot;🌿 木灵根&quot;">​</a></h3><blockquote><p><strong>&quot;灵气恢复 ×1.5，生命恢复 +5&quot;</strong></p></blockquote><ul><li>定位：<strong>续航回复型</strong></li><li>突出优势：灵气恢复速度最快（×1.5），续航能力极强</li><li>额外生命恢复 +5，持久战优势明显</li><li>功法契合：全木系功法（多为辅助/治疗类）享受 <strong>1.5倍威力</strong></li><li>适合玩家：喜欢持续输出、团队辅助的修士</li></ul><h3 id="💧-水灵根" tabindex="-1">💧 水灵根 <a class="header-anchor" href="#💧-水灵根" aria-label="Permalink to &quot;💧 水灵根&quot;">​</a></h3><blockquote><p><strong>&quot;灵气恢复 ×1.3，魔力上限 ×1.2&quot;</strong></p></blockquote><ul><li>定位：<strong>法术均衡型</strong></li><li>突出优势：灵气恢复 + 魔力上限双加成</li><li>水灵根功法偏向控制与范围攻击</li><li>功法契合：全水系功法享受 <strong>1.5倍威力</strong></li></ul><h3 id="🔥-火灵根" tabindex="-1">🔥 火灵根 <a class="header-anchor" href="#🔥-火灵根" aria-label="Permalink to &quot;🔥 火灵根&quot;">​</a></h3><blockquote><p><strong>&quot;伤害 ×1.1，暴击率 +10%&quot;</strong></p></blockquote><ul><li>定位：<strong>极限爆发型</strong></li><li>突出优势：直接伤害加成 + 暴击率，瞬间爆发最高</li><li>火灵根功法多为高伤害攻击型</li><li>功法契合：全火系功法享受 <strong>1.5倍威力</strong></li></ul><h3 id="🪨-土灵根" tabindex="-1">🪨 土灵根 <a class="header-anchor" href="#🪨-土灵根" aria-label="Permalink to &quot;🪨 土灵根&quot;">​</a></h3><blockquote><p><strong>&quot;防御 ×1.15&quot;</strong></p></blockquote><ul><li>定位：<strong>坦克生存型</strong></li><li>突出优势：唯一拥有防御倍率加成的灵根（×1.15）</li><li>适合抗伤害、前排吸收火力的修士</li><li>功法契合：全土系功法（多为防御/护盾类）享受 <strong>1.5倍威力</strong></li></ul><h3 id="🌟-天灵根-稀有" tabindex="-1">🌟 天灵根（稀有） <a class="header-anchor" href="#🌟-天灵根-稀有" aria-label="Permalink to &quot;🌟 天灵根（稀有）&quot;">​</a></h3><blockquote><p><strong>&quot;全属性优秀，功法威力 ×1.2&quot;</strong></p></blockquote><ul><li>定位：<strong>全才万能型</strong></li><li>觉醒概率：仅 <strong>5%</strong>，万中无一</li><li>突破成功率加成 <strong>+20%</strong>（全灵根最高）</li><li>灵气恢复 <strong>×2.0</strong>（全灵根最快）</li><li>所有功法（不限灵根）享受 <strong>×1.2 威力加成</strong></li><li>防御 ×1.1，生命恢复 +2</li><li><strong>同灵根功法同样享受 1.5倍加成</strong></li></ul><blockquote><p>🎯 如果你觉醒了天灵根，恭喜！你是天选之人，所有功法都能发挥更强威力。</p></blockquote><hr><h2 id="灵根与功法契合" tabindex="-1">灵根与功法契合 <a class="header-anchor" href="#灵根与功法契合" aria-label="Permalink to &quot;灵根与功法契合&quot;">​</a></h2><p>功法的 <strong>契合灵根</strong> 字段决定了哪些灵根可以获得额外加成：</p><ul><li><strong>同灵根功法</strong>：灵根与功法契合灵根一致 → 威力 ×<strong>1.5</strong></li><li><strong>天灵根特殊</strong>：所有功法威力 ×<strong>1.2</strong>（无论灵根），且同灵根功法还能叠加 ×1.5</li><li><strong>跨灵根功法</strong>：不契合的灵根使用功法时，只能获得基础威力</li></ul><h3 id="各灵根对应功法一览" tabindex="-1">各灵根对应功法一览 <a class="header-anchor" href="#各灵根对应功法一览" aria-label="Permalink to &quot;各灵根对应功法一览&quot;">​</a></h3><table tabindex="0"><thead><tr><th>灵根</th><th>专属功法</th></tr></thead><tbody><tr><td>金灵根</td><td>灵刃斩、御剑术、金钟罩、天雷引、万剑归宗、大罗天斩</td></tr><tr><td>木灵根</td><td>缠绕术、回春术、生生不息、万象森罗</td></tr><tr><td>水灵根</td><td>水镜盾、缩地成寸、冰封术、沧海横流</td></tr><tr><td>火灵根</td><td>灵气弹、火蛇术、丹火焚天、焚天劫火、万雷归一</td></tr><tr><td>土灵根</td><td>护体罡气、岩铠术、山岳镇压、不动明王、天劫护体</td></tr><tr><td>天灵根</td><td>金丹化神、元婴出窍、化神领域、飞升羽化</td></tr></tbody></table><hr><h2 id="灵根觉醒" tabindex="-1">灵根觉醒 <a class="header-anchor" href="#灵根觉醒" aria-label="Permalink to &quot;灵根觉醒&quot;">​</a></h2><ul><li>进入服务器后自动检测灵根</li><li>五大基础灵根（金/木/水/火/土）各占 19% 概率</li><li>天灵根仅 5% 概率</li><li>无灵根概率为 0%（所有玩家均可修炼）</li><li>灵根一旦确定不可更改</li></ul><hr><h2 id="修炼效率对比" tabindex="-1">修炼效率对比 <a class="header-anchor" href="#修炼效率对比" aria-label="Permalink to &quot;修炼效率对比&quot;">​</a></h2><p>以灵气恢复速度为参考（基础值 × 灵根倍率）：</p><table tabindex="0"><thead><tr><th>灵根</th><th>每秒灵气恢复</th><th>相对效率</th></tr></thead><tbody><tr><td>无灵根</td><td>1.0</td><td>100%</td></tr><tr><td>金/火/土</td><td>1.0</td><td>100%</td></tr><tr><td>水灵根</td><td>1.3</td><td>130%</td></tr><tr><td>木灵根</td><td>1.5</td><td>150%</td></tr><tr><td>天灵根</td><td>2.0</td><td>200%</td></tr></tbody></table>',38)])])}const c=d(a,[["render",i]]);export{b as __pageData,c as default};
